}
6. 代理模式(Proxy) §
#include &lt;iostream&gt;

using std::cout;
using std::endl;

class Subject {
public:
    virtual void request() {
        cout &lt;&lt; &quot;Base&quot; &lt;&lt; endl;
    }
};

class Proxy : public Subject {
    void beforeRequest() {
        cout &lt;&lt; &quot;before&quot; &lt;&lt; endl;
    }

    void afterRequest() {
        cout &lt;&lt; &quot;after&quot; &lt;&lt; endl;
    }

    Subject *subject;

public:
    void request() override {
        beforeRequest();
        subject-&gt;request();
        afterRequest();
    }

    Proxy() {
        subject = new Subject();
    }
};

int main() {
    (new Proxy())-&gt;request();
}
行为模式(Behavioral Pattern) §
1. 命令模式(Command) §
将命令封装成对象

#include&lt;iostream&gt;

using std::cout;
using std::endl;

class Receiver {
public:
    void action() {
        cout &lt;&lt; &quot;Receiver Action&quot; &lt;&lt; endl;
    }
};

class Command {
protected:
    Receiver *receiver{};
public:
    virtual void setReceiver(Receiver *_receiver) {
        receiver = _receiver;
    }

    virtual void execute() = 0;
};

class ConcreteCommand : public Command {
public:
    void execute() override {
        cout &lt;&lt; &quot;Command Execute&quot; &lt;&lt; endl;
        receiver-&gt;action();
    }
};

class Invoker {
    Command *command;
public:
    explicit Invoker(Command *_command) {
        command = _command;
    }

    void call() {
        cout &lt;&lt; &quot;Command Invoke&quot; &lt;&lt; endl;
        command-&gt;execute();
    }
};

int main() {
    Command *cmd = new ConcreteCommand();
    cmd-&gt;setReceiver(new Receiver());
    (new Invoker(cmd))-&gt;call();
}

